database_selections.original_sparql:
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX conf: <http://conference#>

SELECT ?person ?first_name ?last_name ?email ?gender
WHERE {
  ?person rdf:type conf:Person .
  OPTIONAL { ?person conf:has_the_first_name ?first_name . }
  OPTIONAL { ?person conf:has_the_last_name ?last_name . }
  OPTIONAL { ?person conf:has_an_email ?email . }
  OPTIONAL { ?person conf:has_gender ?gender . }
  FILTER (?person IN (<<SUBQUERY_1>>))
}

